// Synthetics API canary.
// Runtime: syn-nodejs-puppeteer-X.Y
// Issues a GET against TARGET_URL and asserts:
//   - HTTP 200
//   - non-empty response body

const synthetics = require('Synthetics');
const log = require('SyntheticsLogger');
const https = require('https');
const http = require('http');
const { URL } = require('url');

const TARGET_URL = process.env.TARGET_URL || 'https://example.com/';

function fetch(target) {
  return new Promise((resolve, reject) => {
    const url = new URL(target);
    const lib = url.protocol === 'https:' ? https : http;
    const req = lib.request(
      {
        method: 'GET',
        hostname: url.hostname,
        port: url.port || (url.protocol === 'https:' ? 443 : 80),
        path: `${url.pathname}${url.search}`,
        headers: { 'User-Agent': 'CloudWatchSynthetics-ApiCanary' },
        timeout: 15000,
      },
      (res) => {
        const chunks = [];
        res.on('data', (c) => chunks.push(c));
        res.on('end', () => {
          resolve({
            status: res.statusCode,
            body: Buffer.concat(chunks).toString('utf8'),
            headers: res.headers,
          });
        });
      },
    );
    req.on('error', reject);
    req.on('timeout', () => req.destroy(new Error('request timed out')));
    req.end();
  });
}

const apiCheck = async function () {
  await synthetics.executeStep('getEndpoint', async function () {
    log.info(`GET ${TARGET_URL}`);
    const res = await fetch(TARGET_URL);
    log.info(`status=${res.status} bytes=${res.body.length}`);

    if (res.status !== 200) {
      throw new Error(`Expected 200, got ${res.status} from ${TARGET_URL}`);
    }
    if (!res.body || res.body.length === 0) {
      throw new Error(`Empty response body from ${TARGET_URL}`);
    }
  });
};

exports.handler = async () => {
  return await apiCheck();
};
